function parseCsvLine(line) {
  const fields = [];
  let i = 0;

  // An empty string is a single empty field
  if (line.length === 0) return [''];

  while (i < line.length) {
    if (line[i] === '"') {
      // quoted field
      i++; // skip opening quote
      let field = '';
      while (i < line.length) {
        if (line[i] === '"') {
          if (line[i + 1] === '"') {
            field += '"';
            i += 2;
          } else {
            i++; // skip closing quote
            break;
          }
        } else {
          field += line[i];
          i++;
        }
      }
      fields.push(field);
      if (i < line.length && line[i] === ',') i++; // skip separator
    } else {
      // unquoted field: read until next comma
      const start = i;
      while (i < line.length && line[i] !== ',') i++;
      fields.push(line.slice(start, i));
      if (i < line.length) i++; // skip comma
    }

    // trailing comma means one more empty field
    if (i === line.length && line[line.length - 1] === ',') {
      fields.push('');
      break;
    }
  }

  return fields;
}

